class Solution {
    public int numberOfArrays(String s, int k) {
        int n = s.length(), mod = (int)1e9 + 7;
        int[] dp = new int[n + 1];
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            long num = 0;
            for (int j = i; j >= 1; j--) {
                num = num * 10 + s[j - 1] - '0';
                if (num > k) break;
                dp[i] = (dp[i] + dp[j - 1]) % mod;
            }
        }
        return dp[n];
    }
}
